// 立即领取
const claimNow = async (link: string, privilege_params: string, privilege_id: string, item: any) => {
    console.log('立即领取', link)
    const sn: any = route.query.sn || ''
    /**
     * 确定领取权益事件上报
     * faculty_id: 学部id
     * rights_id: 权益id
     */
    sensors.track("rights_determine_click", {
        faculty_id: stageIndex.value,
        rights_id: privilege_id,
    });
    // 点击立即领取按钮，结束计时
    const claimEnd = new Date().getTime()
    /**
     * 统计权益领取列表页曝光时长
     * faculty_id: 学部id
     * duration: 曝光时长
     */
    sensors.track("rights_faculty_show", {
        faculty_id: stageIndex.value,
        duration: claimEnd - claimStart,
    });
    // const privilege_pkg_id = process.env.VUE_APP_PRIVILEGE_PKG_ID
    const { data } = await getClaimStatus(privilege_pkg_id, sn, privilege_id)
    if(data.errcode === 0) {
        const isReceive = data.data.is_receive
        if (isReceive === 2) {
            Toast({
                message: '当前已领取过该权益',
            })
            item.status = 2
            hasClaimed.value = true
        } else {
            window.ConnectWebViewBridgeSDK.getUserInfo((res: any) => {
                const {talId }= res
                console.log('立即领取', link)
                const redirect = getUrlStrParam(link, 'redirect')
                const topbar = getUrlStrParam(link, 'topbar')
                let url = ''
                const pattern = /passport/
                // 匹配到passport，则认为是走登录态转移
                if(pattern.test(link)) {
                    console.log('跳转到登录页')
                    const redirectUrl = encodeURIComponent(`${redirect}?privilege_params=${privilege_params}&talId=${talId}&sn=${sn}`)
                    const redirectIndex = link.indexOf('redirect')
                    if(topbar && topbar === 'show') {
                        url = link.slice(0, redirectIndex) + `redirect=${redirectUrl}`
                    } else {
                        url = link.slice(0, redirectIndex) + `redirect=${redirectUrl}&appbar=transparent`
                    }
                } else {
                    // 如果链接没有有参数
                    if (link.indexOf('?') === -1) {
                        url = `${link}?privilege_params=${privilege_params}&talId=${talId}${topbar && topbar === 'show' ? "" : '&appbar=transparent'}&sn=${sn}`
                    } else {
                        url = `${link}&privilege_params=${privilege_params}&talId=${talId}${topbar && topbar === 'show' ? "" : '&appbar=transparent'}&sn=${sn}`
                    }
                }
                window.ConnectWebViewBridgeSDK.jumpToH5Handler({
                    url: url
                })
            })
        }
    } else {
        Toast({
                message: data.errmsg,
        })
    }
     
   
}
const goBack = ()=>{
    const endTime = new Date().getTime()
    if (!showDetail.value && !hasClaimed.value) {
