        sensors.track("rights_home_show", {
            duration: endTime - homePageStart
        })
    } else {
        // 权益领取列表页曝光时长
        sensors.track("rights_faculty_show", {
            faculty_id: stageIndex.value,
            duration: endTime - claimStart,
        });
    }
    // 卡片曝光时长
    sensors.track("rights_home_faculty_show", {
        faculty_id: stageIndex.value,
        duration: endTime - cardStart
    })
    window.ConnectWebViewBridgeSDK.goback();
}

